// 1. Get the data from the OpenAI node specifically
const aiContent = $("AI - Lead Validation (OpenAI)").first().json.choices[0].message.content;
const r = JSON.parse(aiContent).lead;

// 2. Title Case Helper
const tc = s => (s || '').trim().replace(/\b\w/g, c => c.toUpperCase());

// 3. Strip HTML tags from user-controlled strings (prevents XSS in emails and PDF)
const stripHtml = s => (s || '').replace(/<[^>]*>/g, '').trim();

// 4. Phone Formatter Helper
const ph = p => {
  const d = (p || '').replace(/\D/g, '');
  return d.length === 10
    ? d.replace(/(\d{3})(\d{3})(\d{4})/, '$1-$2-$3')
    : (p || '').trim();
};

// 5. Return the cleaned data
return [{
  json: {
    name_clean: stripHtml(tc(r.first_name) + ' ' + tc(r.last_name)),
    phone_clean: ph(r.phone),
    email_clean: (r.email || '').toLowerCase().trim(),

    addr_clean: [
      tc(r.street_address || ''),
      tc(r.city || ''),
      'TX'
    ].filter(Boolean).join(', '),

    issue_clean: stripHtml((r.issue || '').trim()).slice(0, 1000),
    window_count: r.windows
  }
}];

const input = $input.first();
const windows = input.json.windows;
const binary = input.binary || {};
const lead_id = input.json.lead_id;

return windows.map(w => ({
  json: {
    ...w,
    lead_id
  },
  binary: w.photo_key && binary[w.photo_key] ? { photo: binary[w.photo_key] } : {}
}));

const wins = $('Supabase - Fetch All Windows2').all().map(i => i.json);
const pricing = {};
$('Supabase - Fetch Pricing Config1').all().forEach(i => {
  pricing[i.json.service_type] = parseFloat(i.json.base_price);
});

if (Object.keys(pricing).length === 0) {
  throw new Error('Pricing configuration is empty — cannot generate estimate. Check the pricing_config table.');
}

const lead = $('Supabase - Pipeline Window Details Received').first().json;
const issue = lead.issue_description;

// Strip HTML and limit length to prevent prompt injection from notes
const safeText = s => (s || '').replace(/<[^>]*>/g, '').replace(/\n{3,}/g, '\n\n').trim().slice(0, 1000);

// Deduplicate windows by id
const seen = new Set();
const uniqueWins = wins.filter(w => {
  if (seen.has(w.id)) return false;
  seen.add(w.id);
  return true;
});

const winList = uniqueWins.map((w, i) => {
  const svc = w.issue_type === 'Foggy/Broken' ? 'foggy_glass_igu'
    : w.issue_type === 'Full Window Replacement' ? 'full_window_replacement'
    : 'other_service';
  const bp = pricing[svc] || 200;
  const desc = w.issue_type === 'Other' ? `Other (${w.other_description || 'see notes'})` : w.issue_type;
  return `Window ${i+1}: ${desc} | Notes: ${safeText(w.notes) || 'None'} | Base $${bp}`;
}).join('\n');

const prompt = `You are an estimator for Apex Windows TX (foggy glass / window replacement, Dallas-Fort Worth TX).\n\nWINDOWS:\n${winList}\n\nCUSTOMER DESCRIPTION: ${safeText(issue)}\n\nPRICING:\n- Foggy/Broken IGU: $${pricing.foggy_glass_igu || 250}/unit base\n- Full Replacement: $${pricing.full_window_replacement || 650}/unit base\n- Other/Custom: $${pricing.other_service || 200} base\n\nRULES: Assess each window. Apply multiplier 1.0 (standard) to 1.4 (complex) based on notes. Texas tax = 8.25%. Write 2-sentence customer_note (warm). 1-sentence sales_manager_note.\n\nRESPOND WITH ONLY VALID JSON — no markdown, no text outside the JSON:\n{\n  "line_items": [{"window_number":1,"description":"IGU Replacement","base_price":250,"multiplier":1.0,"final_price":250,"complexity_note":"Standard"}],\n  "subtotal":250,"tax_rate":0.0825,"tax_amount":20.63,"total":270.63,\n  "customer_note":"Two sentences.","sales_manager_note":"One sentence."\n}`;

return [{ json: { prompt, lead_id: lead.id, lead_name: lead.name, lead_email: lead.email, lead_phone: lead.phone, lead_address: lead.address } }];

const raw = $input.first().json.choices[0].message.content;
const lead = $('Code - Build AI Prompt').first().json;

try {
  const estimate = JSON.parse(raw);
  return [{ json: {
    estimate,
    parse_ok: true,
    lead_id: lead.lead_id,
    lead_name: lead.lead_name,
    lead_email: lead.lead_email,
    lead_phone: lead.lead_phone,
    lead_address: lead.lead_address
  }}];
} catch(e) {
  return [{ json: {
    estimate: {
      line_items: [{ window_number: 1, description: 'Manual Review Required', base_price: 0, multiplier: 1, final_price: 0, complexity_note: 'AI parse failed' }],
      subtotal: 0,
      tax_rate: 0.0825,
      tax_amount: 0,
      total: 0,
      customer_note: 'We have received your request and are preparing a personalised quote for you.',
      sales_manager_note: 'AI PARSE FAILED - manual estimate required.'
    },
    parse_ok: false,
    raw_response: raw,
    lead_id: lead.lead_id,
    lead_name: lead.lead_name,
    lead_email: lead.lead_email,
    lead_phone: lead.lead_phone,
    lead_address: lead.lead_address
  }}];
}

const lead = $('Supabase - Pipeline Estimate Generated').first().json;
const wins = $('Supabase - Fetch All Windows2').all().map(i => i.json);
const estimate = $('Code - Parse AI Response').first().json.estimate;

// HTML-escape helper — prevents XSS from breaking PDFShift renderer
const esc = s => String(s == null ? '' : s)
  .replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');

// Deduplicate windows
const seen = new Set();
const uniqueWins = wins.filter(w => {
  if (seen.has(w.id)) return false;
  seen.add(w.id);
  return true;
});

const rows = uniqueWins.map((w, i) => {
  const img = w.photo_url
    ? `<a href="${esc(w.photo_url)}" style="color:#1565C0">View Photo</a>`
    : '<em style="color:#aaa">No photo</em>';
  const iss = w.issue_type === 'Other' ? `Other: ${esc(w.other_description || '')}` : esc(w.issue_type);
  return `<tr>
    <td style="padding:8px;border:1px solid #ddd"><b>#${i+1}</b></td>
    <td style="padding:8px;border:1px solid #ddd">${iss}</td>
    <td style="padding:8px;border:1px solid #ddd">${esc(w.notes) || '—'}</td>
    <td style="padding:8px;border:1px solid #ddd">${img}</td>
  </tr>`;
}).join('');

const lineItemRows = estimate.line_items.map(item => `<tr>
  <td style="padding:8px;border:1px solid #ddd">#${item.window_number}</td>
  <td style="padding:8px;border:1px solid #ddd">${esc(item.description)}</td>
  <td style="padding:8px;border:1px solid #ddd">$${item.base_price}</td>
  <td style="padding:8px;border:1px solid #ddd">${item.multiplier}x</td>
  <td style="padding:8px;border:1px solid #ddd">$${item.final_price}</td>
  <td style="padding:8px;border:1px solid #ddd">${esc(item.complexity_note)}</td>
</tr>`).join('');

const html = `<!DOCTYPE html><html><head><meta charset="UTF-8">
<style>
  body{font-family:Arial,sans-serif;margin:28px;color:#333}
  .hdr{background:#1565C0;color:#fff;padding:16px 20px;border-radius:6px}
  h2{color:#1565C0;border-bottom:2px solid #1565C0;padding-bottom:4px}
  table{width:100%;border-collapse:collapse;margin:8px 0}
  th{background:#1565C0;color:#fff;padding:8px;text-align:left}
  .total-row{background:#1565C0;color:#fff;font-weight:bold}
  .foot{margin-top:24px;font-size:11px;color:#999;text-align:center}
</style></head><body>
<div class="hdr">
  <h1 style="margin:0">Apex Windows TX</h1>
  <p style="margin:4px 0 0;opacity:.8">Window Service Request &amp; Estimate</p>
</div>
<h2>Customer Information</h2>
<table>
  <tr><th>Name</th><th>Phone</th><th>Email</th><th>Address</th></tr>
  <tr><td>${esc(lead.name)}</td><td>${esc(lead.phone)}</td><td>${esc(lead.email)}</td><td>${esc(lead.address)}</td></tr>
</table>
<h2>Issue Description</h2>
<p>${esc(lead.issue_description)}</p>
<h2>Window Details (${uniqueWins.length} windows)</h2>
<table>
  <tr><th>#</th><th>Issue Type</th><th>Notes</th><th>Photo</th></tr>
  ${rows}
</table>
<h2>AI Estimate</h2>
<table>
  <tr><th>#</th><th>Description</th><th>Base Price</th><th>Multiplier</th><th>Final Price</th><th>Notes</th></tr>
  ${lineItemRows}
  <tr><td colspan="4" style="padding:8px;border:1px solid #ddd"><b>Subtotal</b></td><td style="padding:8px;border:1px solid #ddd"><b>$${estimate.subtotal}</b></td><td></td></tr>
  <tr><td colspan="4" style="padding:8px;border:1px solid #ddd"><b>Tax (8.25%)</b></td><td style="padding:8px;border:1px solid #ddd"><b>$${estimate.tax_amount}</b></td><td></td></tr>
  <tr class="total-row"><td colspan="4" style="padding:8px">TOTAL</td><td style="padding:8px">$${estimate.total}</td><td></td></tr>
</table>
<p><i>${esc(estimate.customer_note)}</i></p>
<div class="foot">Generated by Apex Windows TX Automated System</div>
</body></html>`;

return [{ json: {
  html_content: html,
  lead_id: lead.id,
  lead_name: lead.name,
  lead_email: lead.email,
  lead_phone: lead.phone,
  lead_address: lead.address,
  estimate_total: estimate.total,
  estimate_id: $('Supabase - Save Estimate').first().json.id
}}];

