const MAX_SIZE = 5 * 1024 * 1024;
const ALLOWED_MIMES = ['image/jpeg', 'image/jpg', 'image/png'];
const ALLOWED_EXTS = ['.jpg', '.jpeg', '.png'];

const webhookData = $('Webhook - Window Details').first();
const form = webhookData.json.body || webhookData.json;
const binary = webhookData.binary || {};

let lead_id = null;
try {
  lead_id = $input.first().json.id || null;
} catch (e) {
  lead_id = null;
}

if (!lead_id) {
  throw new Error('Could not find lead for email: ' + (form.email || 'unknown'));
}

const redactPII = s => {
  if (!s) return s;
  return s
    .replace(/\b\d{3}-\d{2}-\d{4}\b/g, '[SSN REDACTED]')
    .replace(/\b\d{4}[\s-]?\d{4}[\s-]?\d{4}[\s-]?\d{4}\b/g, '[CC REDACTED]');
};

const validatePhoto = (photoData, fileSize, label) => {
  if (fileSize > MAX_SIZE) throw new Error(`${label} photo exceeds 5MB.`);
  if (fileSize > 0) {
    const mime = (photoData.mimeType || '').toLowerCase();
    if (mime && !ALLOWED_MIMES.includes(mime)) {
      throw new Error(`${label}: file type "${mime}" not allowed. Upload JPEG or PNG only.`);
    }
    const fname = (photoData.fileName || '').toLowerCase();
    if (fname && !ALLOWED_EXTS.some(ext => fname.endsWith(ext))) {
      throw new Error(`${label}: file extension not allowed. Upload JPEG or PNG only.`);
    }
  }
};

const windows = [];

if (form.windows_meta) {
  let parsed;
  try {
    parsed = JSON.parse(form.windows_meta);
  } catch (e) {
    throw new Error('Invalid windows_meta JSON: ' + e.message);
  }

  for (const w of parsed) {
    const photoKey = Object.keys(binary).find(key =>
      key.toLowerCase().includes(`w${w.window_number}`)
    ) || null;
    const photoData = photoKey ? binary[photoKey] : null;
    const fileSize = photoData ? parseInt(photoData.fileSize, 10) : 0;

    validatePhoto(photoData || {}, fileSize, `Window ${w.window_number}`);

    windows.push({
      window_number: w.window_number,
      issue_type: form.issue_type || form['Issue Type'] || 'Unknown',
      other_description: form.other_description || form['Other Description (if Other selected above)'] || null,
      notes: redactPII(w.notes || null),
      photo_key: fileSize > 0 ? photoKey : null,
      photo_filename: fileSize > 0 && photoData ? photoData.fileName : null
    });
  }
}

if (windows.length === 0) {
  for (let i = 1; i <= 10; i++) {
    const photoKey = Object.keys(binary).find(key =>
      key.toLowerCase().includes(`w${i}`)
    ) || null;
    const notesKey = `Window ${i} — Notes (location, severity, any details)`;
    const photoData = photoKey ? binary[photoKey] : null;
    const fileSize = photoData ? parseInt(photoData.fileSize, 10) : 0;
    const hasNotes = !!(form[notesKey] && form[notesKey].trim());

    if (!fileSize && !hasNotes) continue;
    validatePhoto(photoData || {}, fileSize, `Window ${i}`);

    windows.push({
      window_number: i,
      issue_type: form['Issue Type'] || form.issue_type || 'Unknown',
      other_description: form['Other Description (if Other selected above)'] || form.other_description || null,
      notes: redactPII(form[notesKey] || null),
      photo_key: fileSize > 0 ? photoKey : null,
      photo_filename: fileSize > 0 && photoData ? photoData.fileName : null
    });
  }
}

if (windows.length === 0) {
  throw new Error('No window details submitted.');
}

return [{
  json: {
    windows,
    window_count: windows.length,
    lead_id,
    issue_type: form.issue_type || form['Issue Type'] || 'Unknown',
    other_description: form.other_description || form['Other Description (if Other selected above)'] || null
  },
  binary
}];
